mapper.update:
UPDATE contract
    JOIN review_task ON contract.id = review_task.contract_id
SET contract.review_status = #{status},
    review_task.status = #{status}
WHERE review_no = #{reviewId}

mapper.select:
SELECT rt.review_no AS reviewId, rt.review_no AS reviewNo, rt.contract_id AS contractId, c.file_name AS contractName, c.file_size AS fileSize, rt.status AS status, rt.overall_score AS overallScore, rt.created_at AS createdAt, rt.completed_at AS completedAt, ( SELECT JSON_OBJECT( 'high', COUNT(CASE WHEN risk_level = 'high' THEN 1 END), 'medium', COUNT(CASE WHEN risk_level = 'medium' THEN 1 END), 'low', COUNT(CASE WHEN risk_level = 'low' THEN 1 END), 'none', COUNT(CASE WHEN risk_level = 'none' THEN 1 END) ) FROM risk_item ri WHERE ri.review_id = rt.review_no ) AS riskSummary FROM review_task rt INNER JOIN contract c ON rt.contract_id = c.id WHERE rt.user_id = #{userId} AND status = "completed"
AND c.file_name LIKE CONCAT('%', #{keyword}, '%')
AND DATE(rt.created_at) >= #{startDate}
AND DATE(rt.created_at) <= #{endDate}
ORDER BY rt.completed_at DESC

SELECT rt.contract_id AS contractId, rt.id AS reviewId, rt.review_no AS reviewNo
FROM review_task rt
INNER JOIN (
    SELECT contract_id, MAX(id) AS max_id
    FROM review_task
    WHERE user_id = #{userId}
      AND contract_id IN

        #{cid}

    GROUP BY contract_id
) latest ON rt.id = latest.max_id
